mapper.insert:
/*
	 상호평가 등록
	 ForumMutDAO.forumMutInsert
*/
INSERT INTO TB_LMS_DSCS_MTL_EVL (
	STD_ID
	, DSCS_ID
	, MTL_EVL_ID
	, SCR
	, OPNN
	, RGTR_ID
	, FRST_INQ_DTTM
	, MDFR_ID
	, MOD_DTTM
) VALUES (
	#{stdNo}
	, #{forumCd}
	, #{mutSn}
	, #{SCR}
	, #{OPNN}
	, #{rgtrId}
	, FN_DTTM()
	, #{mdfrId}
	, FN_DTTM()
)

mapper.update:
/*
	상호평가 수정
	ForumMutDAO.forumMutUpdate
*/
UPDATE TB_LMS_DSCS_MTL_EVL
SET MDFR_ID = #{mdfrId}
	, MOD_DTTM	= FN_DTTM()
	, SCR = #{SCR}
	, OPNN = #{OPNN}
WHERE MTL_EVL_ID = #{mutSn}
